def kmp_search(text: str, pattern: str) -> list[int]:
    if not pattern:
        return []
    lps = compute_lps(pattern)
    matches = []
    i = j = 0
    while i < len(text):
        if pattern[j] == text[i]:
            i += 1; j += 1
        if j == len(pattern):
            matches.append(i - j)
            j = lps[j - 1]
        elif i < len(text) and pattern[j] != text[i]:
            if j != 0:
                j = lps[j - 1]
            else:
                i += 1
    return matches

def compute_lps(pattern: str) -> list[int]:
    lps = [0] * len(pattern)
    length = 0
    i = 1
    while i < len(pattern):
        if pattern[i] == pattern[length]:
            length += 1
            lps[i] = length
            i += 1
        else:
            if length != 0:
                length = lps[length - 1]
            else:
                lps[i] = 0
                i += 1
    return lps
```
**Big-O:** O(n+m). LPS sayesinde backtrack yok.
**Alternatif:** Naive O(n*m), Z-algorithm O(n+m), Rabin-Karp O(n+m) average.

