class AVLNode:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None
        self.height = 1

class AVLTree:
    def insert(self, root, key):
        if not root:
            return AVLNode(key)
        if key < root.key:
            root.left = self.insert(root.left, key)
        else:
            root.right = self.insert(root.right, key)
        root.height = 1 + max(self._height(root.left), self._height(root.right))
        bal = self._balance(root)
        if bal > 1 and key < root.left.key:
            return self._right_rotate(root)
        if bal < -1 and key > root.right.key:
            return self._left_rotate(root)
        if bal > 1 and key > root.left.key:
            root.left = self._left_rotate(root.left)
            return self._right_rotate(root)
        if bal < -1 and key < root.right.key:
            root.right = self._right_rotate(root.right)
            return self._left_rotate(root)
        return root

    def _height(self, n):
        return n.height if n else 0

    def _balance(self, n):
        return self._height(n.left) - self._height(n.right) if n else 0

    def _left_rotate(self, z):
        y, T2 = z.right, y.left
        y.left, z.right = z, T2
        z.height = 1 + max(self._height(z.left), self._height(z.right))
        y.height = 1 + max(self._height(y.left), self._height(y.right))
        return y

    def _right_rotate(self, z):
        y, T3 = z.left, y.right
        y.right, z.left = z, T3
        z.height = 1 + max(self._height(z.left), self._height(z.right))
        y.height = 1 + max(self._height(y.left), self._height(y.right))
        return y
```
**Big-O:** O(log n). Balance faktoru {-1,0,1} arasinda tutulur.
**Alternatif:** Red-Black tree O(log n), daha az rotation.

