def find_bridges(n, adj):
    visited = [False] * n
    disc = [0] * n; low = [0] * n
    parent = [-1] * n; bridges = []; time = 0

    def dfs(u):
        nonlocal time
        visited[u] = True
        disc[u] = low[u] = time; time += 1
        for v in adj[u]:
            if not visited[v]:
                parent[v] = u; dfs(v)
                low[u] = min(low[u], low[v])
                if low[v] > disc[u]: bridges.append((u, v))
            elif v != parent[u]:
                low[u] = min(low[u], disc[v])

    for i in range(n):
        if not visited[i]: dfs(i)
    return bridges
```
