            nr, nc = r + dr, c + dc
            if 0 <= nr < n and 0 <= nc < n and board[nr][nc] == -1:
                next_moves.append((count_moves(nr, nc), nr, nc))
        next_moves.sort()
        for _, nr, nc in next_moves:
            if backtrack(nr, nc, step + 1): return True
        board[r][c] = -1; return False

    backtrack(0, 0, 0); return board
```
